<?php
namespace App\Livewire\Billing\Invoices;
use App\Models\Invoice; use App\Models\PaymentMethod; use App\Services\PaymentConfirmationService; use Illuminate\Support\Facades\Gate; use Livewire\Component; use Masmerise\Toaster\Toaster as Notifier;
class Show extends Component { public Invoice $invoice; public bool $showPaymentModal=false; public ?int $payment_method_id=null; public string $amount='0'; public ?string $transaction_reference=null; public function mount(Invoice $invoice): void { Gate::authorize('view',$invoice); $this->invoice=$invoice->load(['patient','visit','items.service','payments.method','receipts','handoffs.destinationDepartment']); $this->amount=(string)$invoice->balance_amount; } public function receivePayment(PaymentConfirmationService $service): void { Gate::authorize('billing.receive-payment'); $data=$this->validate(['payment_method_id'=>['required','integer'],'amount'=>['required','numeric','min:0.01'],'transaction_reference'=>['nullable','string','max:120']]); $method=PaymentMethod::query()->forCurrentFacility()->findOrFail($data['payment_method_id']); $payment=$service->confirmPayment($this->invoice,$method,(float)$data['amount'],auth()->user(),$data); Notifier::success('payments.saved'); $this->showPaymentModal=false; $this->redirectRoute('billing.invoices.show',$payment->invoice_id); } public function render(){ return view('livewire.billing.invoices.show',['methods'=>PaymentMethod::query()->forCurrentFacility()->where('is_active',true)->orderBy('sort_order')->get()])->layout('components.layouts.app',['title'=>$this->invoice->invoice_number,'description'=>'Invoice details, payer split and payments.']); } }
